import{_ as t,o,c as i,a2 as a}from"./chunks/framework.BWuWLRhz.js";const g=JSON.parse('{"title":"什么是 wikimem？","description":"","frontmatter":{},"headers":[],"relativePath":"zh/guide/what-is-wikimem.md","filePath":"zh/guide/what-is-wikimem.md","lastUpdated":1783734888000}'),r={name:"zh/guide/what-is-wikimem.md"};function d(n,e,m,l,s,c){return o(),i("div",null,[...e[0]||(e[0]=[a('<h1 id="什么是-wikimem" tabindex="-1">什么是 wikimem？ <a class="header-anchor" href="#什么是-wikimem" aria-label="Permalink to &quot;什么是 wikimem？&quot;">​</a></h1><p>wikimem 是面向 AI Agent 的<strong>文件优先记忆管线</strong>：长期记忆以<strong>纯 markdown 文件</strong> 存储（每个分类一个文件，每个 <code>##</code> 标题一个条目），用<strong>内存 BM25 索引</strong>检索， 再由 <strong>wiki-links</strong> —— <code>[[category:item]]</code> 形式的引用 —— 把关键词搜索够不着的 &quot;含义相关&quot;条目连接起来。</p><p>它是一个<strong>零强制依赖</strong>的 Python 库。<code>pip install wikimem</code> 就是完整系统： 存储、检索（含中文，字符 bigram 兜底）、wiki-link 展开、追加式 journal。</p><h2 id="它解决什么问题" tabindex="-1">它解决什么问题 <a class="header-anchor" href="#它解决什么问题" aria-label="Permalink to &quot;它解决什么问题&quot;">​</a></h2><p>&quot;Agent 记忆&quot;通常以基础设施的形态出现：相似度要一个向量数据库，embedding 端点 成了硬依赖，关系还要再上一个图数据库，最后用 docker-compose 把它们捆在一起。 对个人 Agent 来说 —— 数据量是几千条，不是几十亿条 —— 这套栈是头重脚轻的： 基础设施比数据本身还重，数据离开工具就没法读，而每多一层就多一种丢记忆的方式。</p><p>wikimem 把它倒了过来。记忆<strong>就是</strong>一个 markdown 文件夹。其余一切 —— BM25 索引、可选的向量缓存 —— 都是派生状态，随时可以删掉、随时能从文件重建。 本项目的前代设计跑着 mem0 + Qdrant + Neo4j 才做到这个文本文件夹做的事； 图数据库当年买的关联召回，wiki-links 用一次机械的一跳展开就交付了。</p><h2 id="四条设计规则" tabindex="-1">四条设计规则 <a class="header-anchor" href="#四条设计规则" aria-label="Permalink to &quot;四条设计规则&quot;">​</a></h2><p>库里的一切都从这四条推导而来（XnneHangLab ADR-0001 定稿）：</p><ol><li><strong>markdown 文件是唯一事实源。</strong> 每个分类一个文件（<code>memory/preferences.md</code>）， 每个 <code>##</code> 标题一个条目。可以直接阅读、编辑、diff —— 你的编辑器就是管理界面。</li><li><strong>磁盘上没有不可读的真相。</strong> 一切派生产物（索引、向量缓存）都可删除、 可从文件重建。BM25 索引在启动时于内存中构建，永不落盘。</li><li><strong>永不阻塞对话。</strong> 检索是同步的、有 token 预算的、fail-open 的， <strong>0 次 LLM 调用</strong>；记忆写入由宿主异步执行，每轮至多 <strong>1 次</strong> LLM 调用。</li><li><strong>&quot;发生了什么&quot;永远可以回答。</strong> 每次变更向 <code>journal.jsonl</code> 追加一行； 检索可以解释自己的打分。</li></ol><h2 id="一条管线-没有模式" tabindex="-1">一条管线，没有模式 <a class="header-anchor" href="#一条管线-没有模式" aria-label="Permalink to &quot;一条管线，没有模式&quot;">​</a></h2><p>不存在需要选择的&quot;配置模式&quot;。wikimem 只有一条管线；extras 只是解锁可选增强： 装了就自动生效、彼此之间不冲突：</p><table tabindex="0"><thead><tr><th>安装方式</th><th>增加什么</th><th>使用场景</th></tr></thead><tbody><tr><td><code>wikimem</code></td><td>无 —— 零依赖</td><td>功能完整：存储、BM25 检索（中文用字符 bigram）、wiki-links、journal</td></tr><tr><td><code>wikimem[zh]</code></td><td>jieba</td><td>中文关键词召回比 bigram 更准 —— 装上即自动启用，无需任何配置</td></tr><tr><td><code>wikimem[embed]</code></td><td>httpx + numpy</td><td>语义召回（按含义而不是词面匹配）—— 只有传入 <code>embedder</code> 才会启用；端点挂了自动回退 BM25</td></tr><tr><td><code>wikimem[all]</code></td><td>以上全部</td><td>&quot;别让我做选择&quot;选项</td></tr></tbody></table><p>全部装上也不会改变任何行为，直到你真正用到它：分词器在 jieba 可导入时自动采用； embedding 路径只在构造 <code>MemoryIndex</code> 时传入 <code>embedder</code> 才会运行。</p><h2 id="wikimem-不是什么" tabindex="-1">wikimem 不是什么 <a class="header-anchor" href="#wikimem-不是什么" aria-label="Permalink to &quot;wikimem 不是什么&quot;">​</a></h2><ul><li><strong>不是向量数据库。</strong> 有一个可选的向量<em>缓存</em>，但它是派生状态 —— 可删除、可重建、永远不是事实源。</li><li><strong>不是图数据库。</strong> &quot;图&quot;就是文本：条目内容里的 wiki-links。 展开是一次按名字的精确查找，不是图遍历引擎。</li><li><strong>不是笔记软件。</strong> 格式刻意向 Obsidian <em>靠拢</em>（markdown + <code>[[...]]</code>）， 但基本单元是几句话规模的<strong>条目</strong>而非整篇文档，而且写入者通常是抽取 LLM， 不是人。</li><li><strong>不是 Agent 框架。</strong> wikimem 对你的 LLM、prompt、事件循环没有任何意见。 接线是宿主的事 —— 见<a href="/zh/guide/host-integration.html">宿主集成</a>。</li></ul><h2 id="状态" tabindex="-1">状态 <a class="header-anchor" href="#状态" aria-label="Permalink to &quot;状态&quot;">​</a></h2><p>Pre-alpha（<code>0.1.0.dev0</code>），对照 XnneHangLab ADR-0001 按里程碑逐步构建：</p><ul><li><strong>M1 ✅ —— 存储层</strong>：分类文件、条目模型 + 溯源元数据、wiki-link 解析、 <code>journal.jsonl</code>、原子写入</li><li><strong>M2 ✅ —— 检索</strong>：内存 BM25（字符 bigram 兜底，<code>[zh]</code> extra 提供 jieba）、 一跳 wiki-link 展开、token 预算、explain</li><li><strong>M3 ✅ —— embedding 融合</strong>（<code>[embed]</code> extra）：内容哈希向量缓存 （版本化 <code>.npy</code> + 明文 keys）、memmap 分层（1 万条以上二值量化）、 可插拔 <code>VectorIndex</code> 端口、端点不可用时静默回退纯 BM25</li><li><strong>M4 —— CLI</strong>（下一步）：<code>ls / show / grep / explain / graph</code></li></ul><h2 id="许可与致谢" tabindex="-1">许可与致谢 <a class="header-anchor" href="#许可与致谢" aria-label="Permalink to &quot;许可与致谢&quot;">​</a></h2><p>Apache-2.0。抽取 prompt 的设计借鉴自 <a href="https://github.com/NevaMind-AI/memU" target="_blank" rel="noreferrer">memU</a>（Apache-2.0）—— 借鉴设计而非引入 依赖（lab ADR-0002）。BM25 + 余弦的融合公式与 memU ADR-0007 收敛到的一致。</p>',20)])])}const k=t(r,[["render",d]]);export{g as __pageData,k as default};
